Here's a complete implementation:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found." HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set false to dismiss spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            { "Item", SelectedItem }
        });

        SelectedItem = null; // Reset so the same item can be re-selected
    }
}
```

### Key bindings explained

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Shows/hides spinner; **set `false` when done** |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down to reload from API |
| `CollectionView.ItemsSource` | `Items` (ObservableCollection) | Data source — use `ObservableCollection<T>`, never `List<T>` |
| `CollectionView.SelectedItem` | `SelectedItem` (TwoWay) | Tracks current selection |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap → triggers navigation |

### Important notes

- **Reset `SelectedItem` to `null`** after navigating so the same item can be tapped again.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always dismisses.
- **Use `ObservableCollection<T>`** — a plain `List<T>` won't update the UI on changes.
- **Set `x:DataType`** on `DataTemplate` to enable compiled bindings and catch errors at build time.
- **Update collections on the UI thread** via `MainThread.BeginInvokeOnMainThread`.
